   158→  // ===== CAMERA FUNCTIONS =====
   159→
   160→  async function startMockCamera() {
   161→    try {
   162→      setMockCameraError(null)
   163→      if (!navigator.mediaDevices?.getUserMedia) {
   164→        setMockCameraError('Camera not supported in this browser')
   165→        return
   166→      }
   167→      const constraints = [
   168→        { video: { facingMode: 'user' }, audio: true },
   169→        { video: true, audio: true },
   170→        { video: { facingMode: 'user' }, audio: false },
   171→        { video: true, audio: false },
   172→      ]
   173→      let stream: MediaStream | null = null
   174→      for (const c of constraints) {
   175→        try {
   176→          stream = await navigator.mediaDevices.getUserMedia(c)
   177→          const vt = stream.getVideoTracks()[0]
   178→          if (vt?.readyState === 'live') break
   179→          stream.getTracks().forEach(t => t.stop())
   180→          stream = null
   181→        } catch { stream = null }
   182→      }
   183→      if (!stream) {
   184→        setMockCameraError('Could not access camera')
   185→        return
   186→      }
   187→      mockStreamRef.current = stream
   188→      const v = mockVideoRef.current
   189→      if (v) {
   190→        v.srcObject = stream
   191→        try { await v.play() } catch { try { await v.play() } catch {} }
   192→      }
   193→      setMockCameraReady(true)
   194→    } catch (err: any) {
   195→      setMockCameraError(err.message || 'Camera error')
   196→    }
   197→  }
   198→
   199→  function stopMockCamera() {
   200→    if (mockStreamRef.current) {
   201→      mockStreamRef.current.getTracks().forEach(t => t.stop())
   202→      mockStreamRef.current = null
   203→    }
   204→    setMockCameraReady(false)
   205→  }
   206→
   207→  function captureMockFrame(): string | null {
   208→    if (!mockVideoRef.current) return null
   209→    if (!mockCanvasRef.current) {
   210→      mockCanvasRef.current = document.createElement('canvas')
   211→    }
   212→    const canvas = mockCanvasRef.current
   213→    const video = mockVideoRef.current
   214→    canvas.width = 320
   215→    canvas.height = 240
   216→    const ctx = canvas.getContext('2d')
   217→    if (!ctx) return null
   218→    ctx.drawImage(video, 0, 0, 320, 240)
   219→    return canvas.toDataURL('image/jpeg', 0.7)
   220→  }
   221→
   222→  function startMockFrameCapture() {
   223→    mockFramesRef.current = []
   224→    mockPerQuestionFramesRef.current = []
   225→    mockQuestionStartTimeRef.current = Date.now()
   226→    setTimeout(() => {
   227→      const frame = captureMockFrame()
