   229→        mockFramesRef.current.push(frame)
   230→        mockPerQuestionFramesRef.current.push(frame)
   231→      }
   232→    }, 500)
   233→    mockFrameIntervalRef.current = setInterval(() => {
   234→      const frame = captureMockFrame()
   235→      if (frame) {
   236→        if (mockFramesRef.current.length < 20) mockFramesRef.current.push(frame)
   237→        if (mockPerQuestionFramesRef.current.length < 8) mockPerQuestionFramesRef.current.push(frame)
   238→      }
   239→    }, 4000)
   240→  }
   241→
   242→  function stopMockFrameCapture() {
   243→    if (mockFrameIntervalRef.current) {
   244→      clearInterval(mockFrameIntervalRef.current)
   245→      mockFrameIntervalRef.current = null
   246→    }
   247→    if (bodyLanguageIntervalRef.current) {
   248→      clearInterval(bodyLanguageIntervalRef.current)
   249→      bodyLanguageIntervalRef.current = null
   250→    }
   251→  }
   252→
   253→  // ===== SPEECH RECOGNITION =====
   254→
   255→  function startMockSpeechRecognition() {
   256→    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition
   257→    if (!SpeechRecognition) return
   258→
   259→    const recognition = new SpeechRecognition()
   260→    recognition.continuous = true
   261→    recognition.interimResults = true
   262→    recognition.lang = 'en-US'
   263→
   264→    let finalTranscript = ''
   265→
   266→    recognition.onresult = (event: any) => {
   267→      let interim = ''
   268→      for (let i = event.resultIndex; i < event.results.length; i++) {
   269→        const result = event.results[i]
   270→        if (result.isFinal) {
   271→          finalTranscript += result[0].transcript + ' '
   272→        } else {
   273→          interim = result[0].transcript
   274→        }
   275→      }
   276→      const combined = finalTranscript + interim
   277→      setMockLiveTranscript(combined)
   278→      mockLiveTranscriptRef.current = combined
   279→    }
   280→
   281→    recognition.onerror = (event: any) => {
   282→      if (event.error === 'no-speech') {
   283→        try { recognition.start() } catch (_) {}
   284→      }
   285→    }
   286→
   287→    recognition.onend = () => {
   288→      if (candidateRecordingRef.current) {
   289→        try { recognition.start() } catch (_) {}
   290→      }
   291→    }
   292→
   293→    try {
   294→      recognition.start()
   295→      mockRecognitionRef.current = recognition
   296→    } catch (_) {}
   297→  }
   298→
   299→  function stopMockSpeechRecognition() {
   300→    if (mockRecognitionRef.current) {
   301→      try { mockRecognitionRef.current.stop() } catch (_) {}
   302→      mockRecognitionRef.current = null
   303→    }
   304→  }
   305→
   306→  function ensureAudioContext(): AudioContext {
   307→    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
   308→      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)()
   309→    }
   310→    if (audioCtxRef.current.state === 'suspended') {
   311→      audioCtxRef.current.resume()
   312→    }
   313→    return audioCtxRef.current
   314→  }
   315→
   316→  // ===== VOICE FUNCTIONS =====
   317→
   318→  function speakWithBrowserTTS(text: string): Promise<void> {
   319→    return new Promise((resolve) => {
   320→      if (!window.speechSynthesis) {
   321→        console.warn('[browser-tts] speechSynthesis not available')
   322→        resolve()
   323→        return
   324→      }
   325→      window.speechSynthesis.cancel()
   326→      const utterance = new SpeechSynthesisUtterance(text)
   327→      utterance.rate = 1.0
   328→      utterance.pitch = 1.0
   329→      utterance.volume = 1.0
   330→
   331→      let voices = window.speechSynthesis.getVoices()
   332→      if (voices.length === 0) {
   333→        window.speechSynthesis.onvoiceschanged = () => {
   334→          voices = window.speechSynthesis.getVoices()
   335→          const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   336→            || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   337→            || voices.find(v => v.lang.startsWith('en-US'))
   338→            || voices.find(v => v.lang.startsWith('en'))
   339→          if (preferred) utterance.voice = preferred
   340→        }
   341→      } else {
   342→        const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   343→          || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   344→          || voices.find(v => v.lang.startsWith('en-US'))
   345→          || voices.find(v => v.lang.startsWith('en'))
   346→        if (preferred) utterance.voice = preferred
   347→      }
   348→
   349→      const timeout = setTimeout(() => {
   350→        console.warn('[browser-tts] Safety timeout — resolving after 30s')
   351→        resolve()
   352→      }, 30000)
   353→
   354→      const keepAlive = setInterval(() => {
   355→        if (window.speechSynthesis.speaking) {
   356→          window.speechSynthesis.resume()
   357→        } else {
   358→          clearInterval(keepAlive)
   359→        }
   360→      }, 5000)
   361→
   362→      utterance.onend = () => { clearTimeout(timeout); clearInterval(keepAlive); resolve() }
   363→      utterance.onerror = (e) => { clearTimeout(timeout); clearInterval(keepAlive); console.warn('[browser-tts] error:', e); resolve() }
   364→
   365→      window.speechSynthesis.speak(utterance)
   366→      console.log('[browser-tts] Speaking via browser speechSynthesis')
   367→    })
   368→  }
