   370→  async function playInterviewerAudio(text: string) {
   371→    if (!text) return
   372→    setAiSpeaking(true)
   373→    setVoiceError(null)
   374→    try {
   375→      const token = getToken()
   376→      const response = await fetch('/api/interviews/mock/tts', {
   377→        method: 'POST',
   378→        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
   379→        body: JSON.stringify({ text })
   380→      })
   381→
   382→      const contentType = response.headers.get('content-type') || ''
   383→
   384→      if (contentType.includes('application/json')) {
   385→        console.log('[tts-client] TTS API unavailable, falling back to browser speech synthesis')
   386→        await speakWithBrowserTTS(text)
   387→        setAiSpeaking(false)
   388→        if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   389→        return
   390→      }
   391→
   392→      if (!response.ok) {
   393→        console.error('[tts-client] TTS failed:', response.status)
   394→        await speakWithBrowserTTS(text)
   395→        setAiSpeaking(false)
   396→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   397→        return
   398→      }
   399→
   400→      const arrayBuffer = await response.arrayBuffer()
   401→      if (arrayBuffer.byteLength < 100) {
   402→        console.error('[tts-client] Audio too small:', arrayBuffer.byteLength)
   403→        await speakWithBrowserTTS(text)
   404→        setAiSpeaking(false)
   405→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   406→        return
   407→      }
   408→
   409→      const ctx = ensureAudioContext()
   410→
   411→      try {
   412→        const audioBuffer = await ctx.decodeAudioData(arrayBuffer.slice(0))
   413→        if (mockAudioSourceRef.current) {
   414→          try { mockAudioSourceRef.current.stop() } catch (_) {}
   415→        }
   416→        const source = ctx.createBufferSource()
   417→        source.buffer = audioBuffer
   418→        source.connect(ctx.destination)
   419→        mockAudioSourceRef.current = source
   420→
   421→        source.onended = () => {
   422→          setAiSpeaking(false)
   423→          mockAudioSourceRef.current = null
   424→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   425→        }
   426→
   427→        source.start()
   428→        console.log('[tts-client] Playing via Web Audio API')
   429→      } catch (decodeErr) {
   430→        console.warn('[tts-client] Web Audio decode failed, falling back to Audio element:', decodeErr)
   431→        const blob = new Blob([arrayBuffer], { type: 'audio/mpeg' })
   432→        const audioUrl = URL.createObjectURL(blob)
   433→        if (aiAudioRef.current) {
   434→          aiAudioRef.current.pause()
   435→          URL.revokeObjectURL(aiAudioRef.current.src)
   436→        }
   437→        const audio = new Audio(audioUrl)
   438→        aiAudioRef.current = audio
   439→        audio.onended = () => {
   440→          setAiSpeaking(false)
   441→          URL.revokeObjectURL(audioUrl)
   442→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   443→        }
   444→        audio.onerror = () => {
   445→          setAiSpeaking(false)
   446→          URL.revokeObjectURL(audioUrl)
   447→          if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 1000)
   448→        }
   449→        await audio.play()
   450→      }
   451→    } catch (err) {
   452→      console.error('[tts-client] TTS playback error:', err)
   453→      try { await speakWithBrowserTTS(text) } catch (_) {}
   454→      setAiSpeaking(false)
   455→      if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   456→    }
   457→  }
