   459→  async function startVoiceRecording() {
   460→    setVoiceError(null)
   461→    setMockLiveTranscript('')
   462→    mockLiveTranscriptRef.current = ''
   463→    try {
   464→      if (!voiceStreamRef.current) {
   465→        if (mockStreamRef.current && mockStreamRef.current.getAudioTracks().length > 0) {
   466→          const audioTrack = mockStreamRef.current.getAudioTracks()[0]
   467→          voiceStreamRef.current = new MediaStream([audioTrack])
   468→        } else {
   469→          voiceStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true })
   470→        }
   471→      }
   472→
   473→      voiceChunksRef.current = []
   474→
   475→      const audioContext = ensureAudioContext()
   476→      const source = audioContext.createMediaStreamSource(voiceStreamRef.current)
   477→      const analyser = audioContext.createAnalyser()
   478→      analyser.fftSize = 512
   479→      source.connect(analyser)
   480→      analyserRef.current = analyser
   481→      silenceCountRef.current = 0
   482→      const recordingStartedAt = Date.now()
   483→
   484→      silenceIntervalRef.current = setInterval(() => {
   485→        if (!analyserRef.current) return
   486→        // Grace period: don't count silence for first 2.5s to let user start speaking
   487→        if (Date.now() - recordingStartedAt < 2500) return
   488→        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount)
   489→        analyserRef.current.getByteFrequencyData(dataArray)
   490→        const avg = dataArray.reduce((a, b) => a + b, 0) / dataArray.length
   491→        if (avg < 8) {
   492→          silenceCountRef.current++
   493→          setSilenceTimer(Math.round(silenceCountRef.current * 0.2))
   494→          if (silenceCountRef.current >= 25) stopVoiceRecording()
   495→        } else {
   496→          silenceCountRef.current = 0
   497→          setSilenceTimer(0)
   498→        }
   499→      }, 200)
   500→
   501→      const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
   502→        ? 'audio/webm;codecs=opus'
   503→        : MediaRecorder.isTypeSupported('audio/mp4')
   504→          ? 'audio/mp4'
   505→          : 'audio/webm'
   506→
   507→      const recorder = new MediaRecorder(voiceStreamRef.current, { mimeType })
   508→      voiceRecorderRef.current = recorder
   509→
   510→      recorder.ondataavailable = (e) => {
   511→        if (e.data.size > 0) voiceChunksRef.current.push(e.data)
   512→      }
   513→
   514→      recorder.onstop = async () => {
   515→        setCandidateRecording(false)
   516→        candidateRecordingRef.current = false
   517→        if (silenceIntervalRef.current) clearInterval(silenceIntervalRef.current)
   518→        setSilenceTimer(0)
   519→
   520→        if (voiceChunksRef.current.length === 0) return
   521→
   522→        const totalSilenceChecks = silenceCountRef.current
   523→        const currentTranscript = mockLiveTranscriptRef.current
   524→        if (totalSilenceChecks >= 23 && !currentTranscript.trim()) {
   525→          console.log('[voice] Skipping — recording was mostly silence')
   526→          setMockLiveTranscript('')
   527→          setVoiceError('No speech detected. Tap the mic button when ready to speak.')
   528→          return
   529→        }
   530→
   531→        setVoiceProcessing(true)
   532→        voiceProcessingRef.current = true
   533→        try {
   534→          const currentSession = mockSessionRef.current
   535→          if (!currentSession?.id) {
   536→            console.error('[voice] No active session — cannot send voice response')
   537→            setVoiceError('No active interview session. Please restart.')
   538→            setVoiceProcessing(false)
   539→            voiceProcessingRef.current = false
   540→            return
   541→          }
   542→
   543→          const audioBlob = new Blob(voiceChunksRef.current, { type: mimeType })
   544→
   545→          const voicePerQuestionFrames = [...mockPerQuestionFramesRef.current]
   546→          const voiceQuestionDuration = Math.round((Date.now() - mockQuestionStartTimeRef.current) / 1000)
   547→          mockPerQuestionFramesRef.current = []
   548→          mockQuestionStartTimeRef.current = Date.now()
   549→
   550→          const formData = new FormData()
   551→          const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm'
   552→          formData.append('audio', audioBlob, `recording.${ext}`)
   553→          const liveTranscript = mockLiveTranscriptRef.current.trim()
   554→          if (liveTranscript.length >= 5) {
   555→            formData.append('response_text', liveTranscript)
   556→          }
   557→          if (voicePerQuestionFrames.length > 0) {
   558→            formData.append('frames_json', JSON.stringify(voicePerQuestionFrames))
   559→          }
   560→          formData.append('duration_seconds', String(voiceQuestionDuration))
   561→
   562→          let token = getToken()
   563→          const abortController = new AbortController()
   564→          const fetchTimeout = setTimeout(() => abortController.abort(), 28000)
   565→
   566→          let res: Response
   567→          try {
   568→            res = await fetch(`/api/interviews/mock/${currentSession.id}/voice-respond`, {
   569→              method: 'POST',
   570→              headers: { 'Authorization': `Bearer ${token}` },
   571→              body: formData,
   572→              signal: abortController.signal
   573→            })
   574→            // Handle expired token — refresh and retry once
   575→            if (res.status === 401) {
   576→              try {
   577→                const rt = localStorage.getItem('refresh_token')
   578→                if (rt) {
   579→                  const rr = await fetch('/api/auth/refresh', {
   580→                    method: 'POST',
   581→                    headers: { 'Content-Type': 'application/json' },
   582→                    body: JSON.stringify({ refreshToken: rt })
   583→                  })
   584→                  const rd = await rr.json()
   585→                  if (rd.accessToken) {
   586→                    localStorage.setItem('token', rd.accessToken)
   587→                    if (rd.refreshToken) localStorage.setItem('refresh_token', rd.refreshToken)
   588→                    token = rd.accessToken
   589→                    const retryFD = new FormData()
   590→                    retryFD.append('audio', audioBlob, `recording.${ext}`)
   591→                    if (liveTranscript.length >= 5) retryFD.append('response_text', liveTranscript)
   592→                    if (voicePerQuestionFrames.length > 0) retryFD.append('frames_json', JSON.stringify(voicePerQuestionFrames))
   593→                    retryFD.append('duration_seconds', String(voiceQuestionDuration))
   594→                    res = await fetch(`/api/interviews/mock/${currentSession.id}/voice-respond`, {
   595→                      method: 'POST',
   596→                      headers: { 'Authorization': `Bearer ${token}` },
   597→                      body: retryFD,
   598→                      signal: abortController.signal
   599→                    })
   600→                  }
   601→                }
   602→              } catch (refreshErr) { console.warn('[voice] Token refresh failed:', refreshErr) }
   603→            }
   604→          } finally {
   605→            clearTimeout(fetchTimeout)
   606→          }
   607→
   608→          const data = await res.json()
   609→
   610→          if (data.success) {
   611→            voiceRetryCountRef.current = 0
   612→
   613→            const candidateMsg: MockConversationTurn = {
   614→              role: 'candidate',
   615→              text: data.transcribed_text,
   616→              timestamp: new Date().toISOString()
   617→            }
   618→            const cleanedInterviewerMsg = { ...data.interviewer_message, text: deduplicateInterviewerText(data.interviewer_message.text) }
   619→            const textWasDeduped = cleanedInterviewerMsg.text !== data.interviewer_message.text
   620→            setMockSession(prev => prev ? {
   621→              ...prev,
   622→              conversation: [...prev.conversation, candidateMsg, cleanedInterviewerMsg]
   623→            } : null)
   624→            setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
   625→
   626→            if (data.interviewer_audio_base64 && !textWasDeduped) {
   627→              setAiSpeaking(true)
   628→              const audioData = Uint8Array.from(atob(data.interviewer_audio_base64), c => c.charCodeAt(0))
   629→              const ctx = ensureAudioContext()
   630→
   631→              try {
   632→                const audioBuffer = await ctx.decodeAudioData(audioData.buffer.slice(0))
   633→                if (mockAudioSourceRef.current) {
   634→                  try { mockAudioSourceRef.current.stop() } catch (_) {}
   635→                }
   636→                const srcNode = ctx.createBufferSource()
   637→                srcNode.buffer = audioBuffer
   638→                srcNode.connect(ctx.destination)
   639→                mockAudioSourceRef.current = srcNode
   640→                srcNode.onended = () => {
   641→                  setAiSpeaking(false)
   642→                  mockAudioSourceRef.current = null
   643→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   644→                }
   645→                srcNode.start()
   646→                console.log('[voice-respond] Playing AI audio via Web Audio API')
   647→              } catch (decodeErr) {
   648→                console.warn('[voice-respond] Web Audio decode failed, fallback:', decodeErr)
   649→                const blob = new Blob([audioData], { type: 'audio/mpeg' })
   650→                const url = URL.createObjectURL(blob)
   651→                if (aiAudioRef.current) {
   652→                  aiAudioRef.current.pause()
   653→                  URL.revokeObjectURL(aiAudioRef.current.src)
   654→                }
   655→                const audio = new Audio(url)
   656→                aiAudioRef.current = audio
   657→                audio.onended = () => {
   658→                  setAiSpeaking(false)
   659→                  URL.revokeObjectURL(url)
   660→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   661→                }
   662→                audio.onerror = () => {
   663→                  setAiSpeaking(false)
   664→                  URL.revokeObjectURL(url)
   665→                  if (voiceModeRef.current && !data.is_wrapping_up) setTimeout(() => startVoiceRecording(), 1000)
   666→                }
   667→                await audio.play()
   668→              }
   669→            } else {
   670→              // No backend audio or text was deduped (backend audio has question twice) — use frontend TTS
   671→              await playInterviewerAudio(cleanedInterviewerMsg.text)
   672→            }
   673→          } else {
   674→            const errorMsg = data.error || 'Failed to process your response'
   675→            console.warn('[voice] Transcription failed:', errorMsg)
   676→            voiceRetryCountRef.current = 0
   677→            setMockLiveTranscript('')
   678→            if (errorMsg.includes("didn't catch") || errorMsg.includes('Could not transcribe')) {
   679→              setVoiceError('Could not understand your response. Tap the mic button to try again, or type your answer below.')
   680→            } else {
   681→              setVoiceError(errorMsg)
   682→            }
   683→          }
   684→        } catch (err: any) {
   685→          if (err.name === 'AbortError') {
   686→            console.warn('[voice] Request timed out after 28s')
   687→            setVoiceError('The AI is taking too long to respond. Tap the mic to try again, or type your answer below.')
   688→          } else {
   689→            setVoiceError(err.message || 'Voice processing failed. Tap the mic to try again.')
   690→            console.error('Voice response error:', err)
   691→          }
   692→        } finally {
   693→          setVoiceProcessing(false)
   694→          voiceProcessingRef.current = false
   695→        }
   696→      }
   697→
   698→      recorder.start(250)
   699→      setCandidateRecording(true)
   700→      candidateRecordingRef.current = true
   701→
   702→      setMockLiveTranscript('')
   703→      mockLiveTranscriptRef.current = ''
   704→      startMockSpeechRecognition()
   705→    } catch (err: any) {
   706→      console.error('Mic access error:', err)
   707→      setVoiceError('Microphone access denied. Please allow microphone access to use voice mode.')
   708→      setCandidateRecording(false)
   709→      candidateRecordingRef.current = false
   710→    }
   711→  }
